const slugify = (value) => {
  if (value === undefined || value === null) {
    return null;
  }
  const text = String(value).trim().toLowerCase();
  if (!text) {
    return null;
  }
  const hyphenated = text.replace(/\s+/g, '-');
  const cleaned = hyphenated.replace(/[^a-z0-9-]/g, '');
  const collapsed = cleaned.replace(/-+/g, '-').replace(/^-+|-+$/g, '');
  return collapsed.length > 0 ? collapsed : null;
};

const personaSlug = slugify($json.personaSlug ?? $json.personaId ?? $json.persona);
const projectSlug = slugify($json.projectSlug ?? $json.project);
const runId = $json.runId ?? null;

if (!personaSlug) {
  throw new Error('personaSlug is required for Load Persona.');
}

return [{ json: { personaSlug, projectSlug, runId } }];

const response = $json ?? {};
const data = response.data ?? {};
const prompt = data.prompt;
const resolution = data.resolution ?? null;
const candidates = data.candidates ?? [];
if (!prompt || !prompt.content) {
  const message = response.error?.message ?? 'Prompt could not be resolved.';
  throw new Error(message);
}
const context = $('Normalize Inputs').first().json;
return [{
  json: {
    prompt_text: prompt.content,
    system_prompt: prompt.content,
    prompt_key: prompt.promptKey ?? null,
    prompt_metadata: prompt.metadata ?? {},
    resolution,
    candidates,
    persona_slug: context.personaSlug,
    project_slug: context.projectSlug ?? null
  }
}];
